from fastapi import FastAPI, Depends, HTTPException, Security
from fastapi.security import HTTPBearer, HTTPAuthorizationCredentials
import jwt

security = HTTPBearer()
SECRET_KEY = "change-this-in-production"

def verify_token(credentials: HTTPAuthorizationCredentials = Security(security)):
    token = credentials.credentials
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=["HS256"])
        return payload
    except jwt.ExpiredSignatureError:
        raise HTTPException(status_code=401, detail="Token expired")
    except jwt.InvalidTokenError:
        raise HTTPException(status_code=401, detail="Invalid token")

app = FastAPI()

@app.get("/api/v1/runs", dependencies=[Depends(verify_token)])
async def list_runs():
    return {"runs": []}

# Or inject user context from token:
@app.post("/api/v1/runs")
async def create_run(body: AgentRunCreate, user: dict = Depends(verify_token)):
    run = await run_service.create(user_id=user["sub"], query=body.query)
    return run

from fastapi import Request
from fastapi.responses import JSONResponse
from fastapi.exceptions import RequestValidationError
from pydantic import BaseModel
from typing import Optional, Any

class ErrorResponse(BaseModel):
    error: str
    message: str
    details: Optional[Any] = None
    request_id: Optional[str] = None

# Global exception handlers
@app.exception_handler(RequestValidationError)
async def validation_exception_handler(request: Request, exc: RequestValidationError):
    return JSONResponse(
        status_code=422,
        content=ErrorResponse(
            error="VALIDATION_ERROR",
            message="Request body failed validation",
            details=exc.errors(),
        ).model_dump(),
    )

@app.exception_handler(404)
async def not_found_handler(request: Request, exc):
    return JSONResponse(
        status_code=404,
        content=ErrorResponse(
            error="NOT_FOUND",
            message=f"Resource not found: {request.url.path}",
        ).model_dump(),
    )

@app.exception_handler(Exception)
async def generic_exception_handler(request: Request, exc: Exception):
    import traceback, logging
    logging.error(f"Unhandled exception: {traceback.format_exc()}")
    return JSONResponse(
        status_code=500,
        content=ErrorResponse(
            error="INTERNAL_ERROR",
            message="An unexpected error occurred. Please try again.",
        ).model_dump(),
    )

from fastapi import FastAPI, HTTPException, BackgroundTasks
from pydantic import BaseModel
from enum import Enum
import uuid, anthropic
from datetime import datetime

app = FastAPI(title="Agent Run API")
client = anthropic.AsyncAnthropic()
runs_db: dict = {}

class RunStatus(str, Enum):
    PENDING = "pending"
    RUNNING = "running"
    COMPLETED = "completed"
    FAILED = "failed"

class CreateRunRequest(BaseModel):
    query: str
    model: str = "claude-opus-4-5"

async def execute_agent(run_id: str, query: str, model: str):
    """Background task: runs agent and updates run record."""
    try:
        runs_db[run_id]["status"] = RunStatus.RUNNING
        message = await client.messages.create(
            model=model,
            max_tokens=2048,
            messages=[{"role": "user", "content": query}]
        )
        runs_db[run_id].update({
            "status": RunStatus.COMPLETED,
            "result": message.content[0].text,
            "completed_at": datetime.utcnow().isoformat(),
            "usage": {
                "input_tokens": message.usage.input_tokens,
                "output_tokens": message.usage.output_tokens,
            }
        })
    except Exception as e:
        runs_db[run_id].update({
            "status": RunStatus.FAILED,
            "error": str(e),
            "completed_at": datetime.utcnow().isoformat(),
        })

@app.post("/api/v1/runs", status_code=202)  # 202 Accepted: work is async
async def create_run(body: CreateRunRequest, background_tasks: BackgroundTasks):
    run_id = str(uuid.uuid4())
    run = {
        "id": run_id,
        "status": RunStatus.PENDING,
        "query": body.query,
        "model": body.model,
        "created_at": datetime.utcnow().isoformat(),
        "completed_at": None,
        "result": None,
        "error": None,
    }
    runs_db[run_id] = run
    background_tasks.add_task(execute_agent, run_id, body.query, body.model)
    return {**run, "poll_url": f"/api/v1/runs/{run_id}"}

@app.get("/api/v1/runs/{run_id}")
async def get_run(run_id: str):
    if run_id not in runs_db:
        raise HTTPException(status_code=404, detail="Run not found")
    return runs_db[run_id]

@app.get("/api/v1/runs")
async def list_runs(status: RunStatus | None = None, limit: int = 20):
    runs = list(runs_db.values())
    if status:
        runs = [r for r in runs if r["status"] == status]
    return {"items": runs[:limit], "total": len(runs)}
